CREATE OR REPLACE FUNCTION fpb_loan_request_not_clear (AS_REQNO CHAR , AS_METHOD CHAR) RETURNS bigint AS $body$
DECLARE

  ldc_amount bigint;

BEGIN

if as_method = 'P' then
	select sum(monthly_pay_p)
	into STRICT	ldc_amount
	from sc_lon_m_loan_history
	where loan_requestment_no = AS_REQNO
  and   clear_target = '0'
	;
else
	select sum(monthly_pay_i)
	into STRICT	ldc_amount
	from sc_lon_m_loan_history
	where loan_requestment_no = AS_REQNO
  and clear_target = '0'
	;
end if;

  return nvn(ldc_amount);
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
